@js:
(function() {
    try {
        // 1. 请求首页获取最新的分类列表
        var res = java.ajax("https://www.tingyou.fm/");
        var doc = org.jsoup.Jsoup.parse(res);

        // 2. 找到分类入口的 a 标签
        var tags = doc.select(".category-entry__tag");
        var discovery = [];

        for (var i = 0; i < tags.size(); i++) {
            var tag = tags.get(i);
            // 提取分类名称（如：玄幻奇幻）
            var name = tag.select(".category-entry__tag-name").text();
            // 提取分类链接（如：/categories/46）
            var href = tag.attr("href");

            if (name && href) {
                // 3. 按照“阅读”App 要求的格式拼接：名称::链接
                // 加上 sort=comprehensive (综合排序) 和分页占位符
                var url = "https://www.tingyou.fm" + href + "?sort=comprehensive&page={{page}}";
                discovery.push(name + "::" + url);
            }
        }

        // 4. 将数组合并为换行符分隔的字符串返回
        return discovery.join("\n");
    } catch (e) {
        // 容错处理，如果自动抓取失败，返回一个基础的
        return "玄幻奇幻::https://www.tingyou.fm/categories/46?page={{page}}";
    }
})()

