ruleContent.content:
@js:
(function() {
    try {
        var html = String(result);

        // 1. 全局搜索并提取“动态通行证” (Bearer Token)
        var tokenMatch = html.match(/(gAAAAA[a-zA-Z0-9-_=]+)/);

        if (tokenMatch) {
            var token = "Bearer " + tokenMatch[1];
            java.log("🔑 成功挖出通行证: " + token);

            // 2. 尝试模拟抓包看到的 API 发送请求
            var chapterId = baseUrl.split('/').pop(); 

            var requestObj = {
                "url": "https://www.tingyou.fm/api/play_token",
                "method": "POST",
                "headers": {
                    "authorization": token,
                    "x-payload-version": "1",
                    "Referer": baseUrl,
                    "User-Agent": "Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/116.0.0.0 Mobile Safari/537.36",
                    "Origin": "https://www.tingyou.fm",
                    "content-type": "text/plain"
                },
                // 尝试发送基础 ID 测试服务器容忍度
                "body": chapterId 
            };

            // 让开源阅读代为发送请求
            var apiRes = java.ajax(JSON.stringify(requestObj));
            java.log("🌐 API 接口返回数据: " + apiRes);

            // 如果服务器下发了包含 file.hgeuz.cn 的链接，直接拦截返回！
            var streamMatch = apiRes.match(/(https:\/\/file\.hgeuz\.cn\/stream\/[^"'\s\\]+)/);
            if(streamMatch) {
                java.log("🎯 API 拦截成功！");
                return streamMatch[1] + "#.mp3";
            }
        }

        // =======================================================
        // 3. 终极防线：强启阅读 App 内置浏览器播放
        // =======================================================
        java.log("⚠️ API 提取失败，正在强行唤起内置浏览器加载流媒体...");
        java.startBrowserAwait(baseUrl, "听友FM - 正在加载");

        return "💡 正在后台浏览器解析音频，请稍候...";

    } catch (e) {
        return "代码运行异常: " + e.message;
    }
})()

ruleExplore.bookList:
@js:
(function() {
    try {
        const html = String(result);
        const match = html.match(/id="__NUXT_DATA__"[^>]*>([\s\S]+?)<\/script>/);
        if (!match) return [];
        const data = JSON.parse(match[1]);

        // 指针还原函数
        const getV = (idx) => (idx !== null && idx !== undefined) ? data[idx] : "";

        let bookListIndices = [];

        // --- 全自动寻址逻辑 ---
        for (let i = 0; i < data.length; i++) {
            let item = data[i];
            if (item && typeof item === 'object') {
                // 分类页特征：对象包含 data 属性（指向书籍索引数组）且包含 pages 分页属性
                if (item.data !== undefined && item.pages !== undefined) {
                    let potentialList = data[item.data];
                    if (Array.isArray(potentialList) && potentialList.length > 0) {
                        bookListIndices = potentialList;
                        break;
                    }
                }
            }
        }

        // --- 备选寻址（如果上面没找到） ---
        if (bookListIndices.length === 0) {
            for (let i = 0; i < data.length; i++) {
                if (Array.isArray(data[i]) && data[i].length > 3) {
                    let first = data[data[i][0]];
                    // 只要数组里第一个元素指向的东西有标题或ID，就认定是书籍数组
                    if (first && typeof first === 'object' && (first.title || first.id)) {
                        bookListIndices = data[i];
                        break;
                    }
                }
            }
        }

        return bookListIndices.map(idx => {
            let b = data[idx];
            if (!b || typeof b !== 'object') return null;

            let title = getV(b.title);
            let author = getV(b.author);
            let teller = getV(b.teller);
            let cover = getV(b.cover_url) || getV(b.cover);

            // 组合作者和演播
            let displayAuthor = author;
            if (teller && teller !== author && teller !== "佚名") {
                displayAuthor = author + " (" + teller + ")";
            }

            return {
                name: title,
                auth: displayAuthor || "未知",
                pic: cover,
                intro: getV(b.desc),
                cat: b.categoryName ? getV(b.categoryName) : (b.status === 99 ? "连载" : "完结"),
                count: (b.count || b.chapterTotal || "") + "期",
                url: "/albums/" + getV(b.id)
            };
        }).filter(b => b && b.name);
    } catch (e) {
        return [];
    }
})()

ruleSearch.bookList:
@js:
(function() {
    try {
        // 1. 提取 JSON 字符串并解析
        const match = result.match(/id="__NUXT_DATA__"[^>]*>([\s\S]+?)<\/script>/);
        if (!match) return [];
        const data = JSON.parse(match[1]);

        // 2. 定位搜索结果列表在数组中的位置
        // 观察数据：{"searchResults":4} -> index 4 是 {"list":5} -> index 5 是索引数组 [6, 16...]
        let bookIndices = [];
        for (let i = 0; i < data.length; i++) {
            if (data[i] && typeof data[i] === 'object' && data[i].list !== undefined && Array.isArray(data[data[i].list])) {
                bookIndices = data[data[i].list];
                break;
            }
        }

        // 3. 遍历索引还原书籍对象
        return bookIndices.map(idx => {
            const item = data[idx];
            if (!item) return null;

            // 还原逻辑：字段对应的值是 data 数组中的索引
            return {
                title: data[item.title] || "",
                author: data[item.author] || data[item.teller] || "未知",
                desc: data[item.desc] || "",
                cover: data[item.cover] || "",
                cat: data[item.categoryName] || "",
                status: item.status === 1 ? "连载" : "完结",
                count: (item.chapterTotal || "") + "期",
                url: "/albums/" + data[item.id]
            };
        }).filter(b => b !== null);
    } catch (e) {
        return [];
    }
})()

