@js:
(function(){
    try {
        // 1. 获取详情页源码，提取底层 Nuxt 数据
        var match = String(result).match(/id="__NUXT_DATA__"[^>]*>([\s\S]+?)<\/script>/);
        if (!match) return [{name: "未找到底层数据", url: ""}];

        var data = JSON.parse(match[1]);
        var list = [];

        // 2. 从当前页面链接中提取书籍 ID
        var bookMatch = baseUrl.match(/albums\/(\d+)/);
        var bookId = bookMatch ? bookMatch[1] : "";

        var seen = {}; // 用于去重

        // 3. 遍历底层数组，寻找所有“章节”特征对象
        for (var i = 0; i < data.length; i++) {
            var item = data[i];

            // 章节对象的特征：包含 title, id, index (序号)
            if (item && typeof item === 'object' && 'title' in item && 'id' in item && 'index' in item) {
                var chId = data[item.id];
                var chTitle = data[item.title];
                var chIndex = data[item.index]; // 真实的集数序号，如 1, 2, 3

                // 拦截无效数据并去重
                if (chId && chTitle && typeof chTitle === 'string' && !seen[chId]) {
                     seen[chId] = true;
                     list.push({
                         name: chTitle,
                         // 拼凑出标准的音频播放页链接
                         url: "https://www.tingyou.fm/audios/" + bookId + "/" + chIndex,
                         sortIdx: chIndex // 记录序号用于排序
                     });
                }
            }
        }

        // 4. 按真实的集数序号从小到大排序，防止乱序
        list.sort(function(a, b){ return a.sortIdx - b.sortIdx; });

        return list;
    } catch(e) {
        return [{name: "解析崩溃: " + e.message, url: ""}];
    }
})()
